# ===== GENERATION AND MERGE LOGIC =====

def build_quiz_entry(slug, data):
    quiz_id = f"history_{slug}_1"
    questions = []
    for i, qdata in enumerate(data["questions"], 1):
        qid = f"hist_{slug}_{i}"
        questions.append({
            "id": qid,
            "text": qdata["text"],
            "options": qdata["options"],
            "correctAnswer": qdata["correctAnswer"],
            "explanation": "",
            "category": "History"
        })
    return {
        "id": quiz_id,
        "title": data["title"],
        "createdAt": DATE,
        "questions": questions,
        "language": "marathi",
        "tag": "History Topic",
        "topicOnly": True
    }

def build_topic_entry(slug, data, quiz_entry):
    return {
        "id": f"topic_history_{slug}",
        "name": data["title"],
        "category": "History",
        "questionIds": [q["id"] for q in quiz_entry["questions"]]
    }

def main():
    quizzes = json.load(open('public/quizzes.json', 'r', encoding='utf-8'))
    topics = json.load(open('public/topics.json', 'r', encoding='utf-8'))

    existing_quiz_ids = {q["id"] for q in quizzes}
    existing_topic_ids = {t["id"] for t in topics}

    added_q = 0
    added_t = 0

    for slug, data in ALL_QUIZZES.items():
        quiz_entry = build_quiz_entry(slug, data)
        if quiz_entry["id"] not in existing_quiz_ids:
            quizzes.append(quiz_entry)
            added_q += 1
            print(f"Added quiz: {quiz_entry['id']} ({len(quiz_entry['questions'])} questions)")
        else:
            print(f"Quiz already exists: {quiz_entry['id']}")

        topic_entry = build_topic_entry(slug, data, quiz_entry)
        if topic_entry["id"] not in existing_topic_ids:
            topics.append(topic_entry)
            added_t += 1
            print(f"Added topic: {topic_entry['id']}")
        else:
            print(f"Topic already exists: {topic_entry['id']}")

    with open('public/quizzes.json', 'w', encoding='utf-8') as f:
        json.dump(quizzes, f, ensure_ascii=False, indent=2)

    with open('public/topics.json', 'w', encoding='utf-8') as f:
        json.dump(topics, f, ensure_ascii=False, indent=2)

    print(f"\nDone! Added {added_q} quizzes and {added_t} topics.")
    print(f"Total quizzes: {len(quizzes)}, Total topics: {len(topics)}")

if __name__ == "__main__":
    main()
